import api from './app/client';

import type { PublicHoliday } from '../types/holiday';

export type { PublicHoliday };

export const publicHolidayService = {
  // Helper to format year to exactly "2025-26"
  formatFY: (year: number) => {
    const nextYearShort = (year + 1).toString().slice(-2);
    return `${year}-${nextYearShort}`;
  },

  getAll: (mode: 'Year' | 'FinancialYear' = 'Year', year?: number): Promise<PublicHoliday[]> => {
    const displayYear = year || new Date().getFullYear();
    const url = mode === 'FinancialYear' 
      ? `/public-holidays/financial/${publicHolidayService.formatFY(displayYear)}` 
      : '/public-holidays';
    
    // For Calendar Year, we pass the year as a query param
    const params = mode === 'Year' ? { year: displayYear } : {};
    return api.get(url, { params }).then((r) => {
      // Handle paginated response if it exists
      if (r.data && Array.isArray(r.data.data)) {
        return r.data.data;
      }
      // Handle direct array response
      return Array.isArray(r.data) ? r.data : [];
    });
  },

  getPaged: (pageIndex: number, pageSize: number, mode: 'Year' | 'FinancialYear' = 'Year', year?: number): Promise<unknown> => {
    const displayYear = year || new Date().getFullYear();
    const url = mode === 'FinancialYear'
      ? `/public-holidays/financial/${publicHolidayService.formatFY(displayYear)}`
      : '/public-holidays';

    // Pagination params are always required
    const params: { pageIndex: number; pageSize: number; year?: number } = { pageIndex, pageSize };
    if (mode === 'Year') params.year = displayYear;

    return api.get(url, { params }).then((r) => r.data);
  },

  create: (data: Record<string, unknown>) => api.post('/public-holidays', formDataFix(data)),
  update: (id: string, data: Record<string, unknown>) => api.put(`/public-holidays/${id}`, formDataFix(data)),
  delete: (id: string) => api.delete(`/public-holidays/${id}`),
};

// Helper to ensure date strings are clean if necessary
const formDataFix = (data: Record<string, unknown>) => ({
    ...data,
    holidayOnDate: typeof data.holidayOnDate === 'string' ? data.holidayOnDate.split('T')[0] : data.holidayOnDate
});
